#include <bits/stdc++.h>
using namespace std;
unsigned long long s=1,n;
int main() {
	cin>>n;
	for(unsigned long long i=1; i<n*2; i+=2) {
		for(unsigned long long j=0;j<s;j++){
			cout<<" ";
		}
		for(unsigned long long j=0;j<i;j++){
			cout<<"*";
		}
		cout<<"\n";
		s++;
	}
//	cout<<"yangjun是傻逼！yangjun是傻逼！yangjun是傻逼！yangjun是傻逼！";
	return 0;
}
